            const diff = Math.abs(a - b);
            const sum = Math.abs(a + b);
            const minVal = Math.min(diff, sum);
            const maxVal = Math.max(diff, sum);

            if (minVal <= minAbs && maxVal >= maxAbs) {
                count++;
            }
        }
    }

